insert into public.culture_items (
	category,
	item_type,
	collection,
	title,
	period_label,
	location_label,
	short_summary,
	sort_order
)
select
	'music',
	'knowledge_card',
	source_items.collection,
	source_items.title,
	source_items.period_label,
	source_items.location_label,
	source_items.short_summary,
	source_items.sort_order
from source_items
where not exists (
	select 1
	from public.culture_items existing_items
	where existing_items.category = 'music'
		and existing_items.collection = source_items.collection
		and existing_items.title = source_items.title
);

