), all_music_items as (
	select culture_items.id, culture_items.collection, culture_items.title
	from public.culture_items
	where culture_items.category = 'music'
		and culture_items.collection in ('music_artists', 'music_albums', 'music_songs')
)
insert into public.culture_prompts (
	item_id,
	prompt_direction,
	prompt_type,
	question,
	answer,
	answer_aliases,
	choices,
	sort_order
)
select
	all_music_items.id,
	source_prompts.prompt_direction,
	source_prompts.prompt_type,
	source_prompts.question,
	source_prompts.answer,
	source_prompts.answer_aliases,
	source_prompts.choices,
	source_prompts.sort_order
from source_prompts
join all_music_items
	on all_music_items.collection = source_prompts.collection
	and all_music_items.title = source_prompts.item_title
where not exists (
	select 1
	from public.culture_prompts existing_prompts
	where existing_prompts.item_id = all_music_items.id
		and existing_prompts.question = source_prompts.question
);

